{"code": "import urllib.request, json, re

# Fetch Ars Technica AI feed
url = "https://feeds.arstechnica.com/arstechnica/technology-lab"
req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
with urllib.request.urlopen(req, timeout=10) as r:
    content = r.read().decode('utf-8', errors='ignore')

items = re.findall(r'<item>(.*?)</item>', content, re.DOTALL)
count = 0
for item in items:
    if 'ai' in item.lower() or 'artificial' in item.lower() or 'machine learning' in item.lower() or 'llm' in item.lower():
        title = re.search(r'<title>(.*?)</title>', item)
        link = re.search(r'<link>(.*?)</link>', item)
        dt = re.search(r'<pubDate>(.*?)</pubDate>', item)
        if title:
            print(f"- {title.group(1).strip()}")
        if link:
            print(f"  {link.group(1).strip()[:80]}")
        if dt:
            print(f"  Date: {dt.group(1).strip()}")
        count += 1
        if count >= 3:
            break"}
